import React from 'react';
import { Card, Stack, Box, Divider, Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const { city, temperature, condition, humidity, windSpeed, unit = 'C', forecast } = props;

  return (
    <Card shadow="md" padding={24} radius="lg">
      <Stack gap={24}>
        {/* Header Section */}
        <Stack gap={4} align="center">
          <Heading level={2} color="var(--ggui-color-onSurface)">{city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{condition}</Text>
        </Stack>

        {/* Temperature Hero */}
        <Stack gap={8} align="center">
          <Heading level={1} color="var(--ggui-color-onSurface)">
            {temperature}°{unit}
          </Heading>
        </Stack>

        {/* Metrics Row */}
        <Box padding="var(--ggui-spacing-4, 16px)" borderRadius="var(--ggui-shape-radius-md, 8px)" background="var(--ggui-color-surfaceVariant, #f4f4f5)">
          <Stack direction="horizontal" justify="between">
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
              <Text variant="label" color="var(--ggui-color-onSurface)">{humidity}%</Text>
            </Stack>
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
              <Text variant="label" color="var(--ggui-color-onSurface)">{windSpeed} km/h</Text>
            </Stack>
          </Stack>
        </Box>

        <Divider />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between" gap={16}>
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={8}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{item.day ?? '-'}</Text>
              <Text size="xl">{item.icon ?? '?'}</Text>
              <Stack align="center" gap={2}>
                <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">{item.high ?? 0}°</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{item.low ?? 0}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Box, Card, Stack, Text, Heading } from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: Array<Element>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-success-100, #dcfce7)',
  'noble-gas': 'var(--ggui-color-info-100, #cffafe)',
  'alkali-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'halogen': 'var(--ggui-color-error-100, #fee2e2)',
  'transition-metal': 'var(--ggui-color-neutral-100, #f3f4f6)',
  'default': 'var(--ggui-color-surfaceVariant, #f4f4f5)'
};

export default function GeneratedComponent(props: Props) {
  const [query, setQuery] = useState('');
  const [selected, setSelected] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    if (!query) return props.elements;
    const lowerQuery = query.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(lowerQuery) ||
        el.symbol?.toLowerCase().includes(lowerQuery)
    );
  }, [props.elements, query]);

  const categories = useMemo(() => Array.from(new Set(props.elements.map(e => e.category || 'default'))), [props.elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Heading level={1}>Periodic Table</Heading>

        <SearchField
          value={query}
          onChange={setQuery}
          placeholder="Search by name or symbol (e.g. Hydrogen, H)..."
        />

        <Box 
          style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(18, 1fr)', 
            gap: 'var(--ggui-spacing-1, 4px)',
            minHeight: '400px'
          }}
        >
          {props.elements.map((el, i) => {
            const isMatch = filteredElements.includes(el);
            return (
              <button
                key={i}
                aria-label={`${el.name}, Atomic Number ${el.atomicNumber}`}
                onClick={() => setSelected(el)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  aspectRatio: '1/1',
                  background: CATEGORY_COLORS[el.category || 'default'] ?? CATEGORY_COLORS.default,
                  border: `1px solid var(--ggui-color-outline, #d4d4d8)`,
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  cursor: 'pointer',
                  opacity: isMatch ? 1 : 0.2,
                  transition: 'transform 200ms ease, opacity 200ms ease',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  position: 'relative',
                  padding: 'var(--ggui-spacing-1, 4px)'
                }}
                onMouseOver={(e) => { if(isMatch) e.currentTarget.style.transform = 'scale(1.05)' }}
                onMouseOut={(e) => { e.currentTarget.style.transform = 'scale(1)' }}
              >
                <Text variant="caption" style={{ position: 'absolute', top: 2, left: 4 }}>{el.atomicNumber}</Text>
                <Heading level={5}>{el.symbol}</Heading>
              </button>
            );
          })}
        </Box>

        {selected && (
          <Card padding="var(--ggui-spacing-4, 16px)">
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={3}>{selected.name} ({selected.symbol})</Heading>
              <Text>Atomic Number: {selected.atomicNumber}</Text>
              <Text>Atomic Weight: {selected.atomicWeight}</Text>
              <Text>Category: {selected.category}</Text>
            </Stack>
          </Card>
        )}

        <Card padding="var(--ggui-spacing-4, 16px)">
          <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
            {categories.map(cat => (
              <Stack key={cat} direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
                <Box style={{ width: 16, height: 16, background: CATEGORY_COLORS[cat] ?? CATEGORY_COLORS.default, borderRadius: 'var(--ggui-shape-radius-sm, 4px)' }} />
                <Text variant="caption">{cat}</Text>
              </Stack>
            ))}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
